/***************************************
 * QAcademy — Offline Packs API (V1 Core)
 * Keeps ONLY:
 *   - GET  health
 *   - GET  builder.meta        (token-optional; if token provided -> course gate enforced)
 *   - GET  downloads.allowance (token required)
 *   - POST downloads.create    (token required)
 ***************************************/

const BUILD = 'offlinepacks-v1-2025-12-24-core+meta';

// Portal DB Spreadsheet ID
const PORTAL_DB_ID = '1Aq0IaPOjC1Vo4bQb8aP0S0bO5EaeUx_4oYUlnJ2g2vc';

// Tabs in Portal DB
const TAB_COURSES        = 'courses';        // course_id, sheet_id, status...
const TAB_USERS          = 'users';
const TAB_TOKENS         = 'tokens';
const TAB_PRODUCTS       = 'products';       // product_id, kind, courses_included, status...
const TAB_SUBSCRIPTIONS  = 'subscriptions';  // user_id, product_id, status, start_utc, expires_utc...
const TAB_OFFLINE_PACKS  = 'offline_packs';

// New automated Limits changing
// Config tab (Portal DB)
const TAB_CONFIG = 'config';

// Config keys (Portal DB -> config tab)
const CFG_OFFLINE_MAX_QUESTIONS     = 'offline_max_questions';
const CFG_OFFLINE_PACKS_PER_COURSE  = 'offline_packs_per_course';

// Fallback defaults if config tab/key missing
const DEFAULT_OFFLINE_MAX_QUESTIONS    = 50;
const DEFAULT_OFFLINE_PACKS_PER_COURSE = 3;


// offline_packs schema (LOCKED order)
const OFFLINE_PACKS_DEFAULT_HEADER = [
  'pack_id',
  'user_id',
  'course_id',
  'pack_name',
  'created_at',
  'question_count',
  'topics',
  'difficulties',
  'question_ids',
  'watermark',
  'status'
];

/* ==================== HTTP HANDLERS ==================== */

function doGet(e) {
  try {
    const action = (e.parameter.action || '').trim().toLowerCase();

    if (action === 'health') {
      return json_({ ok: true, build: BUILD, ts: new Date().toISOString() });
    }

    if (action === 'builder.meta') {
      const courseId = reqParam_(e, 'course_id');

      // token-optional: if provided, enforce course access
      optionalCourseGate_(e, courseId);

      const meta = getBuilderMeta_(courseId);
      return json_(meta);
    }

    if (action === 'downloads.allowance') {
      const token    = (e.parameter.token || '').trim();
      const courseId = reqParam_(e, 'course_id');

      if (!token) return jsonError_('Missing token', 400);

      const auth = verifyToken_(token);
      const ss = SpreadsheetApp.openById(PORTAL_DB_ID);

      const info = resolveAllowance_(ss, auth.user_id, courseId);
      return json_(info);
    }

    if (action === 'downloads.pack') {
      const token  = (e.parameter.token || '').trim();
      const packId = reqParam_(e, 'pack_id');

      if (!token) return jsonError_('Missing token', 400);

      const auth = verifyToken_(token);
      const ss = SpreadsheetApp.openById(PORTAL_DB_ID);

      const res = getOfflinePackForRender_(ss, auth.user_id, packId);
      return json_(res);
    }
if (action === 'downloads.list') {
  const token  = (e.parameter.token || '').trim();
  if (!token) return jsonError_('Missing token', 400);

  const auth = verifyToken_(token);
  const ss = SpreadsheetApp.openById(PORTAL_DB_ID);

  const courseId = (e.parameter.course_id || '').trim();
  const status   = (e.parameter.status   || '').trim();
  const q        = (e.parameter.q        || '').trim();

  const cursor = (e.parameter.cursor || '').trim();
  const limit  = parseInt((e.parameter.limit || '20'), 10);

  const out = listOfflinePacks_(ss, auth.user_id, {
    course_id: courseId,
    status: status,
    q: q,
    cursor: cursor,
    limit: isFinite(limit) ? Math.max(1, Math.min(50, limit)) : 20
  });

  return json_(out);
}

    return jsonError_('Unknown action', 400);
  } catch (err) {
    return jsonError_(err.message || String(err), 500);
  }
}

function doPost(e) {
  try {
    const action = (e.parameter.action || '').trim().toLowerCase();

    if (action === 'downloads.create') {
      const token = (e.parameter.token || '').trim();
      if (!token) return jsonError_('Missing token', 400);

      const raw = readRawPayload_(e);
      if (!raw) return jsonError_('Missing payload', 400);

      const payload = JSON.parse(raw);
      const auth = verifyToken_(token);

      const ss = SpreadsheetApp.openById(PORTAL_DB_ID);
      const result = createOfflinePack_(ss, auth.user_id, payload);

      return json_(result);
    }

    return jsonError_('Unknown action', 400);
  } catch (err) {
    return jsonError_(err.message || String(err), 500);
  }
}

/* ==================== BUILDER META ==================== */

function getBuilderMeta_(courseId) {
  const sheetId = getCourseSheetId_(courseId);
  const items = readItems_(sheetId);

  const portalSS = SpreadsheetApp.openById(PORTAL_DB_ID);
  const maxN = getOfflineMaxQuestions_(portalSS, items.length)

  const mainTopicSet = new Set();
  const diffSet = new Set();

  const topicCounts = Object.create(null);
  const difficultyCounts = Object.create(null);
  const topicDiffCounts = Object.create(null);

  const conceptSet = new Set();
  const conceptCounts = Object.create(null);

  items.forEach(r => {
    const topicRaw = String(r.topic || '').trim();
    const main = mainTopic_(topicRaw);
    const dRaw = String(r.difficulty || '').trim();

    if (main) {
      mainTopicSet.add(main);
      topicCounts[main] = (topicCounts[main] || 0) + 1;

      if (dRaw) {
        if (!topicDiffCounts[main]) topicDiffCounts[main] = Object.create(null);
        topicDiffCounts[main][dRaw] = (topicDiffCounts[main][dRaw] || 0) + 1;
      }
    }

    if (dRaw) {
      diffSet.add(dRaw);
      difficultyCounts[dRaw] = (difficultyCounts[dRaw] || 0) + 1;
    }

    // concept = part after ":" (or full topic if no colon)
    if (topicRaw) {
      const idx = topicRaw.indexOf(':');
      const concept = (idx >= 0) ? topicRaw.slice(idx + 1).trim() : topicRaw;
      if (concept) {
        conceptSet.add(concept);
        conceptCounts[concept] = (conceptCounts[concept] || 0) + 1;
      }
    }
  });

  return {
    ok: true,
    course_id: String(courseId || '').trim(),
    topics_main: Array.from(mainTopicSet).sort((a,b)=>a.localeCompare(b)),
    difficulties: Array.from(diffSet).sort((a,b)=>a.localeCompare(b)),
    maxN: maxN,
    total: items.length,
    topic_counts: topicCounts,
    difficulty_counts: difficultyCounts,
    topic_difficulty_counts: topicDiffCounts,
    concept_suggestions: Array.from(conceptSet).sort((a,b)=>a.localeCompare(b)),
    concept_counts: conceptCounts
  };
}

/* ==================== DOWNLOADS: ALLOWANCE ==================== */

function resolveAllowance_(ss, userId, courseId) {
  const gate = getSubscriptionGateForCourse_(ss, userId, courseId);
  const packsLimit = getOfflinePacksPerCourse_(ss);

  const base = {
    ok: true,
    course_id: String(courseId || '').trim().toUpperCase(),
    downloads_per_course: packsLimit,
    used_this_period: 0,
    remaining: 0,
    period_start: null,
    subscription: {
      status: gate.status,
      is_trial: gate.is_trial
    },
    blocked_reason: null
  };

  if (!gate.allowed) {
    base.ok = false;
    base.blocked_reason = gate.blocked_reason;
    return base;
  }

  const used = countOfflinePacksSince_(ss, userId, courseId, gate.period_start);
  base.used_this_period = used;
  base.remaining = Math.max(0, packsLimit - used);
  base.period_start = gate.period_start ? gate.period_start.toISOString() : null;

  return base;
}

/**
 * Gate logic (V1 locked):
 * - Must have ACTIVE subscription including course_id
 * - Trial users blocked
 * - period_start = subscription.start_utc (fallback Date(0) if missing)
 *
 * Trial detection (current implementation):
 * - products.kind === "trial" => trial
 *
 * If your DB marks trial differently, tell me and we’ll align precisely.
 */
function getSubscriptionGateForCourse_(ss, userId, courseId) {
  const shSubs = ss.getSheetByName(TAB_SUBSCRIPTIONS);
  const shProd = ss.getSheetByName(TAB_PRODUCTS);

  // For downloads, do NOT fail-open
  if (!shSubs || !shProd) {
    return {
      allowed: false,
      blocked_reason: 'not_subscribed',
      status: 'MISSING_TABLES',
      is_trial: false,
      period_start: null
    };
  }

  const subsVals = shSubs.getDataRange().getValues();
  const prodVals = shProd.getDataRange().getValues();
  if (subsVals.length < 2 || prodVals.length < 2) {
    return {
      allowed: false,
      blocked_reason: 'not_subscribed',
      status: 'EMPTY_TABLES',
      is_trial: false,
      period_start: null
    };
  }

  const HS = headerMap_(subsVals[0].map(s => String(s).trim().toLowerCase()));
  const HP = headerMap_(prodVals[0].map(s => String(s).trim().toLowerCase()));

  const iSubUid   = HS['user_id'];
  const iSubPid   = HS['product_id'];
  const iSubStat  = HS['status'];
  const iSubStart = HS['start_utc'];
  const iSubExp   = HS['expires_utc'];

  const iProdId      = HP['product_id'];
  const iProdStatus  = HP['status'];
  const iProdCourses = HP['courses_included'];
  const iProdKind    = HP['kind'];

  if (iSubUid == null || iSubPid == null || iSubStat == null) {
    return { allowed:false, blocked_reason:'not_subscribed', status:'BAD_SUB_HEADERS', is_trial:false, period_start:null };
  }
  if (iProdId == null || iProdCourses == null) {
    return { allowed:false, blocked_reason:'not_subscribed', status:'BAD_PROD_HEADERS', is_trial:false, period_start:null };
  }

  // Active products map
  const productsById = {};
  for (let p = 1; p < prodVals.length; p++) {
    const row = prodVals[p];
    const pid = String(row[iProdId] || '').trim().toUpperCase();
    if (!pid) continue;

    const pStatus = (iProdStatus != null) ? String(row[iProdStatus] || '').trim().toLowerCase() : '';
    if (pStatus && pStatus !== 'active') continue;

    productsById[pid] = row;
  }

  const now = new Date();
  const wantCourse = String(courseId || '').trim().toUpperCase();
  if (!wantCourse) {
    return { allowed:false, blocked_reason:'not_subscribed', status:'NO_COURSE', is_trial:false, period_start:null };
  }

  // Choose best ACTIVE subscription that includes the course
  let best = null;

  for (let s = 1; s < subsVals.length; s++) {
    const row = subsVals[s];
    if (String(row[iSubUid] || '').trim() !== String(userId).trim()) continue;

    const status = String(row[iSubStat] || '').trim().toUpperCase();
    if (status !== 'ACTIVE') continue;

    const start = (iSubStart != null) ? asDateOrNull_(row[iSubStart]) : null;
    const exp   = (iSubExp   != null) ? asDateOrNull_(row[iSubExp])   : null;

    if (start && now < start) continue;
    if (exp && now >= exp) continue;

    const pid = String(row[iSubPid] || '').trim().toUpperCase();
    if (!pid) continue;

    const prodRow = productsById[pid];
    if (!prodRow) continue;

    const coursesRaw = String(prodRow[iProdCourses] || '').trim();
    if (!coursesRaw) continue;

    const tokens = coursesRaw.split(',').map(x => String(x || '').trim().toUpperCase()).filter(Boolean);
    const includes = (tokens.indexOf('ALL') >= 0) || (tokens.indexOf(wantCourse) >= 0);
    if (!includes) continue;

    let isTrial = false;
    if (iProdKind != null) {
      const kind = String(prodRow[iProdKind] || '').trim().toLowerCase();
      if (kind === 'trial') isTrial = true;
    }

    const candidate = {
      status: 'ACTIVE',
      is_trial: isTrial,
      period_start: start || new Date(0),
      expires: exp || null
    };

    if (!best) best = candidate;
    else {
      // Prefer later expiry; if one has no expiry treat as “best”
      if (!best.expires && candidate.expires) continue;
      if (!candidate.expires && best.expires) { best = candidate; continue; }
      if (!best.expires && !candidate.expires) { best = candidate; continue; }
      if (candidate.expires && best.expires && candidate.expires > best.expires) best = candidate;
    }
  }

  if (!best) {
    return {
      allowed: false,
      blocked_reason: 'renew_required',
      status: 'EXPIRED',
      is_trial: false,
      period_start: null
    };
  }

  if (best.is_trial) {
    return {
      allowed: false,
      blocked_reason: 'trial_not_allowed',
      status: 'ACTIVE',
      is_trial: true,
      period_start: best.period_start
    };
  }

  return {
    allowed: true,
    blocked_reason: null,
    status: 'ACTIVE',
    is_trial: false,
    period_start: best.period_start
  };
}

function countOfflinePacksSince_(ss, userId, courseId, periodStart) {
  const sh = ss.getSheetByName(TAB_OFFLINE_PACKS);
  if (!sh) return 0;

  const values = sh.getDataRange().getValues();
  if (values.length < 2) return 0;

  const H = headerMap_(values[0].map(s => String(s).trim().toLowerCase()));

  const iUid  = H['user_id'];
  const iCid  = H['course_id'];
  const iAt   = H['created_at'];
  const iStat = H['status'];

  if (iUid == null || iCid == null || iAt == null) return 0;

  const uid = String(userId).trim();
  const cid = String(courseId).trim().toUpperCase();

  let count = 0;
  for (let r = 1; r < values.length; r++) {
    const row = values[r];

    if (String(row[iUid] || '').trim() !== uid) continue;
    if (String(row[iCid] || '').trim().toUpperCase() !== cid) continue;

    const status = (iStat != null) ? String(row[iStat] || '').trim().toLowerCase() : 'active';
    if (status !== 'active') continue;

    const created = asDateOrNull_(row[iAt]);
    if (!created) continue;

    if (periodStart && created < periodStart) continue;

    count += 1;
  }
  return count;
}


function getUsedOfflineQuestionIdsSince_(ss, userId, courseId, periodStart) {
  const sh = ss.getSheetByName(TAB_OFFLINE_PACKS);
  if (!sh) return new Set();

  const values = sh.getDataRange().getValues();
  if (values.length < 2) return new Set();

  const H = headerMap_(values[0].map(s => String(s).trim().toLowerCase()));

  const iUid  = H['user_id'];
  const iCid  = H['course_id'];
  const iAt   = H['created_at'];
  const iStat = H['status'];
  const iQids = H['question_ids'];

  if (iUid == null || iCid == null || iAt == null || iQids == null) return new Set();

  const uid = String(userId).trim();
  const cid = String(courseId).trim().toUpperCase();

  const pStart = periodStart ? asDateOrNull_(periodStart) : null;

  const used = new Set();

  for (let r = 1; r < values.length; r++) {
    const row = values[r];

    if (String(row[iUid] || '').trim() !== uid) continue;
    if (String(row[iCid] || '').trim().toUpperCase() !== cid) continue;

    const status = (iStat != null) ? String(row[iStat] || '').trim().toLowerCase() : 'active';
    if (status !== 'active') continue;

    const created = asDateOrNull_(row[iAt]);
    if (!created) continue;
    if (pStart && created < pStart) continue;

    const raw = row[iQids];
    if (!raw) continue;

    try {
      const arr = JSON.parse(String(raw));
      if (Array.isArray(arr)) {
        arr.forEach(id => {
          const s = String(id || '').trim();
          if (s) used.add(s);
        });
      }
    } catch (_) {
      // Ignore malformed JSON in old rows
    }
  }

  return used;
}

/* ==================== DOWNLOADS: CREATE ==================== */

function ensureOfflinePacksSheet_(ss) {
  let sh = ss.getSheetByName(TAB_OFFLINE_PACKS);
  if (!sh) {
    sh = ss.insertSheet(TAB_OFFLINE_PACKS);
    sh.appendRow(OFFLINE_PACKS_DEFAULT_HEADER);
  } else {
    ensureHeader_(sh, OFFLINE_PACKS_DEFAULT_HEADER);
  }
  return sh;
}

function createOfflinePack_(ss, userId, payload) {
  const courseId = must_(payload.course_id, 'payload.course_id required');

  // 1) Gate + allowance
  const allowance = resolveAllowance_(ss, userId, courseId);
  if (!allowance.ok) {
    return { ok: false, blocked_reason: allowance.blocked_reason };
  }
  if (allowance.remaining < 1) {
    return { ok: false, blocked_reason: 'limit_reached' };
  }

  // 2) Validate + sanitize
  const packNameRaw = String(payload.pack_name || '').trim();
  const packName = (packNameRaw.length >= 3 ? packNameRaw : 'Offline Pack').slice(0, 60);
  const packsLimit = allowance.downloads_per_course;

// We'll clamp n AFTER we know items. length (so we can cap correctly)
  const nRequested = (payload.n != null ? payload.n : payload.question_count) || 10;

const topicsRaw = sanitizeStringArray_(payload.topics);

// ✅ Filtering list: ignore intent tokens
let topicsFilter = topicsRaw
  .filter(t => !/^CONCEPT:/i.test(t))
  .filter(t => !/^SEARCH:/i.test(t))
  .filter(t => String(t).trim() !== '__ALL_TOPICS__');

// ✅ If user said "all topics", then do NOT topic-filter at all
if (topicsRaw.includes('__ALL_TOPICS__')) topicsFilter = [];

  let diffs = sanitizeStringArray_(payload.difficulties);
if (!diffs.length) {
  diffs = ['Easy', 'Moderate', 'Hard'];
}

  const conceptQuery = String(payload.concept || '').toLowerCase().trim();
  const conceptChoices = Array.isArray(payload.concepts)
    ? payload.concepts.map(c => String(c || '').toLowerCase().trim()).filter(Boolean)
    : [];

  // 3) Build pool from course items (same logic as your former builder-style)
  const sheetId = getCourseSheetId_(courseId);
  const items = readItems_(sheetId);
  const maxQuestions = getOfflineMaxQuestions_(ss, items.length);
  const nReq = clampInt_(nRequested, 1, maxQuestions);


  let pool = items.filter(r => {
// Topic filter (ignore audit tokens)
let topicOk = true;
if (topicsFilter.length) {
  topicOk = topicsFilter.some(t => {
    if (String(t).indexOf(':') !== -1) return same_(r.topic, t);  // exact topic
    return same_(mainTopic_(r.topic), t);                         // main group
  });
}


    // Difficulty filter
    let diffOk = true;
    if (diffs.length) diffOk = diffs.some(d => same_(r.difficulty, d));

    // Concept filter
    let conceptOk = true;
    if (conceptChoices.length) {
      const hay = (String(r.topic || '') + ' ' + String(r.rationale || '')).toLowerCase();
      conceptOk = conceptChoices.some(c => hay.indexOf(c) !== -1);
    } else if (conceptQuery) {
      const hay = (String(r.topic || '') + ' ' + String(r.stem || '') + ' ' + String(r.rationale || '')).toLowerCase();
      conceptOk = hay.indexOf(conceptQuery) !== -1;
    }

    return topicOk && diffOk && conceptOk;
  });

  if (!pool.length) {
    return { ok: false, blocked_reason: 'no_items_match' };
  }

const n = Math.min(nReq, pool.length);

// 4) Prefer-unused sampling (OFFLINE ONLY)
//    - Use unused first within the current subscription period
//    - Only repeat if unused pool is exhausted
const seed = makeSeed_();

// allowance.period_start is an ISO string (or null). We can pass it through as-is;
// helper will parse it into a Date safely.
const usedSet = getUsedOfflineQuestionIdsSince_(ss, userId, courseId, allowance.period_start);

const unusedCandidates = [];
const usedCandidates   = [];

for (let i = 0; i < pool.length; i++) {
  const it = pool[i];
  const id = String(it.item_id || '').trim();
  if (!id) continue;

  if (usedSet.has(id)) usedCandidates.push(it);
  else unusedCandidates.push(it);
}

const takeUnused = Math.min(n, unusedCandidates.length);
const needMore   = n - takeUnused;

const pickedUnused = (takeUnused > 0) ? sample_(unusedCandidates, takeUnused, seed + ':U') : [];
const pickedUsed   = (needMore > 0) ? sample_(usedCandidates, needMore, seed + ':R') : [];

const sampled = pickedUnused.concat(pickedUsed);


  // 5) Persist snapshot row (LOCKED serialization)
  const packId = 'PACK_' + Utilities.getUuid().replace(/-/g, '').slice(0, 24);

// Watermark snapshot (LOCKED fields for cover/footer/watermark)
const prof = getUserProfileForWatermark_(ss, userId);
const ownerName = String(prof.owner_name || '').trim() || 'QAcademy Student';
const ownerEmailMask = maskEmail_(prof.owner_email);

const watermarkObj = {
  pack_id: packId,
  user_id: String(userId).trim(),
  owner_name: ownerName,
  owner_email_mask: ownerEmailMask,
  owner_label: buildOwnerLabel_(ownerName, ownerEmailMask)
};


  const sh = ensureOfflinePacksSheet_(ss);
  const header = ensureHeader_(sh, OFFLINE_PACKS_DEFAULT_HEADER);

  const rowObj = {
    pack_id:        packId,
    user_id:        String(userId).trim(),
    course_id:      String(courseId).trim().toUpperCase(),
    pack_name:      packName,
    created_at:     new Date().toISOString(),
    question_count: n,
    topics:         JSON.stringify(topicsRaw),
    difficulties:   JSON.stringify(diffs),
    question_ids:   JSON.stringify(sampled.map(x => String(x.item_id))), // ✅ JSON array string
    watermark:      JSON.stringify(watermarkObj),
    status:         'active'
  };

  const row = header.map(h => (h in rowObj) ? rowObj[h] : '');
  sh.appendRow(row);

  return {
    ok: true,
    pack_id: packId,
    course_id: String(courseId).trim().toUpperCase(),
    question_count: n,
    unused_selected: pickedUnused.length,
    reused_selected: pickedUsed.length,
    used_this_period: allowance.used_this_period + 1,
    remaining: Math.max(0, packsLimit - (allowance.used_this_period + 1)),
    period_start: allowance.period_start
  };
}

function getOfflinePackForRender_(ss, userId, packId) {
  const sh = ss.getSheetByName(TAB_OFFLINE_PACKS);
  if (!sh) return { ok: false, error: 'offline_packs table missing', code: 500 };

  const values = sh.getDataRange().getValues();
  if (values.length < 2) return { ok: false, error: 'pack_not_found', code: 404 };

  const H = headerMap_(values[0].map(s => String(s).trim().toLowerCase()));

  const iPack = H['pack_id'];
  const iUid  = H['user_id'];
  const iCid  = H['course_id'];
  const iName = H['pack_name'];
  const iAt   = H['created_at'];
  const iN    = H['question_count'];
  const iTop  = H['topics'];
  const iDif  = H['difficulties'];
  const iQids = H['question_ids'];
  const iWm   = H['watermark'];
  const iStat = H['status'];

  if (iPack == null || iUid == null || iCid == null || iQids == null) {
    return { ok: false, error: 'BAD_OFFLINE_PACKS_HEADERS', code: 500 };
  }

  const wantPack = String(packId || '').trim();
  const wantUid  = String(userId || '').trim();

  let row = null;
  for (let r = 1; r < values.length; r++) {
    if (String(values[r][iPack] || '').trim() === wantPack) {
      row = values[r];
      break;
    }
  }

  if (!row) return { ok: false, error: 'pack_not_found', code: 404 };

  // Owner check
  const owner = String(row[iUid] || '').trim();
  if (owner !== wantUid) return { ok: false, error: 'not_owner', code: 403 };

  // Status check
  const status = (iStat != null) ? String(row[iStat] || '').trim().toLowerCase() : 'active';
  if (status && status !== 'active') return { ok: false, error: 'pack_inactive', code: 403 };

  const courseId = String(row[iCid] || '').trim().toUpperCase();
  const packName = (iName != null) ? String(row[iName] || '').trim() : 'Offline Pack';
  const createdAt = (iAt != null) ? String(row[iAt] || '').trim() : '';
  const qCount = (iN != null) ? Number(row[iN]) : null;

  // Parse arrays safely
  const topics = parseJsonArray_(iTop != null ? row[iTop] : '[]');
  const diffs  = parseJsonArray_(iDif != null ? row[iDif] : '[]');
  const qids   = parseJsonArray_(row[iQids]);

  if (!qids.length) return { ok: false, error: 'pack_has_no_questions', code: 500 };

  // Watermark snapshot (kept as object if possible)
  const wm = parseJsonObject_(iWm != null ? row[iWm] : null, { pack_id: wantPack, user_id: wantUid });

  // Hydrate items by id (keep order from qids)
  const items = hydrateItemsByIds_(courseId, qids);

  // If some IDs missing from sheet, still return what we can + a warning
  const missing = qids.filter(id => !items._byId[String(id || '').trim()]);
  const hydrated = qids
    .map(id => items._byId[String(id || '').trim()])
    .filter(Boolean)
    .map((it) => ({
      item_id: String(it.item_id || '').trim(),
      topic: String(it.topic || '').trim(),
      stem: String(it.stem || '').trim(),
      options: {
        A: String(it.option_a || '').trim(),
        B: String(it.option_b || '').trim(),
        C: String(it.option_c || '').trim(),
        D: String(it.option_d || '').trim()
      },
      correct: String(it.correct || '').trim()
    }));

  return {
    ok: true,
    pack: {
      pack_id: wantPack,
      course_id: courseId,
      pack_name: packName,
      created_at: createdAt,
      question_count: (qCount != null && isFinite(qCount)) ? qCount : hydrated.length,
      topics: topics,
      difficulties: diffs,
      watermark: wm
    },
    items: hydrated,
    warning: missing.length ? { missing_item_ids: missing.slice(0, 50), missing_count: missing.length } : null
  };
}

function listOfflinePacks_(ss, userId, opts) {
  const sh = ss.getSheetByName(TAB_OFFLINE_PACKS);
  if (!sh) return { ok: true, items: [], meta: { total: 0, next_cursor: null } };

  const values = sh.getDataRange().getValues();
  if (values.length < 2) return { ok: true, items: [], meta: { total: 0, next_cursor: null } };

  const H = headerMap_(values[0].map(s => String(s).trim().toLowerCase()));

  const iPack = H['pack_id'];
  const iUid  = H['user_id'];
  const iCid  = H['course_id'];
  const iName = H['pack_name'];
  const iAt   = H['created_at'];
  const iN    = H['question_count'];
  const iStat = H['status'];

  if (iPack == null || iUid == null) {
    return { ok:false, error:'BAD_OFFLINE_PACKS_HEADERS', code:500 };
  }

  const uid = String(userId || '').trim();

  const wantCourse = String((opts && opts.course_id) || '').trim().toUpperCase();
  const wantStatus = String((opts && opts.status) || '').trim().toLowerCase();
  const q = String((opts && opts.q) || '').trim().toLowerCase();

  const limit = (opts && opts.limit) ? Number(opts.limit) : 20;
  const offset = (() => {
    const raw = String((opts && opts.cursor) || '').trim();
    if (!raw) return 0;
    const n = parseInt(raw, 10);
    return isFinite(n) && n >= 0 ? n : 0;
  })();

  // 1) collect + filter (user-owned only)
  const all = [];
  for (let r = 1; r < values.length; r++) {
    const row = values[r];

    if (String(row[iUid] || '').trim() !== uid) continue;

    const courseId = (iCid != null) ? String(row[iCid] || '').trim().toUpperCase() : '';
    if (wantCourse && courseId !== wantCourse) continue;

    const statusRaw = (iStat != null) ? String(row[iStat] || '').trim().toLowerCase() : 'active';
    const status = (statusRaw === 'active') ? 'active' : 'inactive';
    if (wantStatus && status !== wantStatus) continue;

    const packName = (iName != null) ? String(row[iName] || '').trim() : '';
    if (q) {
      const hay = (packName + ' ' + courseId).toLowerCase();
      if (hay.indexOf(q) === -1) continue;
    }

    const createdAt = (iAt != null) ? String(row[iAt] || '').trim() : '';
    const qCount = (iN != null) ? Number(row[iN]) : null;

    all.push({
      pack_id: String(row[iPack] || '').trim(),
      course_id: courseId,
      pack_name: packName || 'Offline Pack',
      created_at: createdAt,
      question_count: (qCount != null && isFinite(qCount)) ? qCount : null,
      status: status
    });
  }

  // 2) sort: newest first
  all.sort((a,b) => String(b.created_at||'').localeCompare(String(a.created_at||'')));

  const total = all.length;
  const next = (offset + limit < total) ? String(offset + limit) : null;

  // 3) translate course_id → course_name (backend)
  const courseNameMap = getCourseNameMap_(ss);

  const pageItems = all.slice(offset, offset + limit).map(p => ({
    pack_id: p.pack_id,
    course_id: p.course_id,
    course_name: courseNameMap[p.course_id] || p.course_id,
    pack_name: p.pack_name,
    created_at: p.created_at,
    question_count: p.question_count,
    status: p.status
  }));

  return {
    ok: true,
    items: pageItems,
    meta: {
      total: total,
      next_cursor: next
    }
  };
}


/* ==================== COURSE + ITEMS ==================== */

function getCourseSheetId_(courseId) {
  const ss = SpreadsheetApp.openById(PORTAL_DB_ID);
  const sh = ss.getSheetByName(TAB_COURSES);
  if (!sh) throw new Error(`Missing "${TAB_COURSES}" tab in Portal DB`);

  const values = sh.getDataRange().getValues();
  if (!values.length) throw new Error('Empty courses table');

  const header = values[0].map(s => String(s).trim().toLowerCase());
  const rCourse = colIndex_(header, 'course_id');
  const rSheet  = colIndex_(header, 'sheet_id');
  const rStatus = colIndex_(header, 'status');

  const want = String(courseId || '').trim().toUpperCase();

  for (let i = 1; i < values.length; i++) {
    const row = values[i];
    const cId = String(row[rCourse] || '').trim().toUpperCase();
    if (cId === want) {
      const status = String(row[rStatus] || '').toLowerCase();
      if (status && status !== 'active') throw new Error(`Course "${want}" is not active`);
      const sid = String(row[rSheet] || '').trim();
      if (!sid) throw new Error(`No sheet_id for course "${want}"`);
      return sid;
    }
  }
  throw new Error(`Course not found: ${want}`);
}

function readItems_(sheetId) {
  const ss = SpreadsheetApp.openById(sheetId);
  const sh = ss.getSheetByName('items');
  if (!sh) throw new Error('Missing "items" tab');

  const values = sh.getDataRange().getValues();
  if (values.length < 2) return [];

  const header = values[0].map(s => String(s).trim().toLowerCase());

  const idx = Object.fromEntries([
    'item_id','stem','option_a','option_b','option_c','option_d',
    'correct','rationale','topic','difficulty'
  ].map(k => [k, colIndexOptional_(header, k)]));

  const out = [];
  for (let i = 1; i < values.length; i++) {
    const row = values[i];
    const obj = {
      item_id:    getCell_(row, idx.item_id),
      stem:       getCell_(row, idx.stem),
      option_a:   getCell_(row, idx.option_a),
      option_b:   getCell_(row, idx.option_b),
      option_c:   getCell_(row, idx.option_c),
      option_d:   getCell_(row, idx.option_d),
      correct:    getCell_(row, idx.correct),
      rationale:  getCell_(row, idx.rationale),
      topic:      getCell_(row, idx.topic),
      difficulty: getCell_(row, idx.difficulty)
    };
    out.push(obj);
  }
  return out.filter(r => r.item_id);
}

/* ==================== AUTH + OPTIONAL GATE ==================== */

function verifyToken_(token) {
  if (!token) throw new Error('Missing token');

  const ss = SpreadsheetApp.openById(PORTAL_DB_ID);
  const now = new Date();

  const shTok = ss.getSheetByName(TAB_TOKENS);
  if (!shTok) throw new Error('Tokens table not found');

  const valsTok = shTok.getDataRange().getValues();
  if (valsTok.length < 2) throw new Error('Token not found');

  const HT = headerMap_(valsTok[0].map(s => String(s).trim().toLowerCase()));

  const iToken   = HT['token'];
  const iUserId  = HT['user_id'];
  const iActive  = HT['active'];
  const iExpires = HT['expires_utc'];

  if (iToken == null || iUserId == null) throw new Error('Tokens table missing token/user_id columns');

  let match = null;

  for (let r = 1; r < valsTok.length; r++) {
    const row = valsTok[r];
    if (String(row[iToken]).trim() !== token) continue;

    if (iActive != null && !isTruthy_(row[iActive])) throw new Error('Token inactive');

    if (iExpires != null) {
      const exp = asDateOrNull_(row[iExpires]);
      if (exp && now >= exp) throw new Error('Token expired');
    }

    match = row;
    break;
  }

  if (!match) throw new Error('Invalid token');

  const userId = String(match[iUserId] || '').trim();
  if (!userId) throw new Error('Token has no user_id');

  return { user_id: userId };
}

function optionalCourseGate_(e, courseId) {
  const token = (e.parameter.token || '').trim();
  if (!token) return;
  const auth = verifyToken_(token);

  const ss = SpreadsheetApp.openById(PORTAL_DB_ID);
  const gate = getSubscriptionGateForCourse_(ss, auth.user_id, courseId);
  if (!gate.allowed) throw new Error('No active access to this course');
}

function hydrateItemsByIds_(courseId, itemIds) {
  const sheetId = getCourseSheetId_(courseId);
  const items = readItems_(sheetId);

  const byId = Object.create(null);
  for (let i = 0; i < items.length; i++) {
    const id = String(items[i].item_id || '').trim();
    if (id) byId[id] = items[i];
  }

  return { _byId: byId };
}

function parseJsonArray_(cell) {
  try {
    const raw = (cell == null) ? '[]' : String(cell);
    const v = JSON.parse(raw);
    return Array.isArray(v) ? v : [];
  } catch (_) {
    return [];
  }
}

function parseJsonObject_(cell, fallbackObj) {
  try {
    if (cell == null) return fallbackObj || {};
    const v = JSON.parse(String(cell));
    return (v && typeof v === 'object' && !Array.isArray(v)) ? v : (fallbackObj || {});
  } catch (_) {
    return fallbackObj || {};
  }
}
function getCourseNameMap_(ss) {
  const sh = ss.getSheetByName(TAB_COURSES);
  if (!sh) return {};

  const v = sh.getDataRange().getValues();
  if (v.length < 2) return {};

  const H = headerMap_(v[0].map(x => String(x).trim().toLowerCase()));
  const iId   = H['course_id'];
const iName =
  H['course_name'] != null ? H['course_name'] :
  H['title']       != null ? H['title'] :
  H['name'];

  const map = {};
  for (let r = 1; r < v.length; r++) {
    const id = String(v[r][iId] || '').trim().toUpperCase();
    const nm = String(v[r][iName] || '').trim();
    if (id) map[id] = nm || id;
  }
  return map;
}


function getUserProfileForWatermark_(ss, userId) {
  const sh = ss.getSheetByName(TAB_USERS);
  if (!sh) throw new Error(`Missing "${TAB_USERS}" tab`);

  const v = sh.getDataRange().getValues();
  if (v.length < 2) throw new Error('Users table empty');

  const H = headerMap_(v[0].map(h => String(h).trim().toLowerCase()));

  const iUid = H['user_id'];
  const iName = H['name'];
  const iForename = H['forename'];
  const iSurname = H['surname'];
  const iEmail = H['email'];

  if (iUid == null || iEmail == null) {
    throw new Error('Users table missing required columns');
  }

  const want = String(userId).trim();

  for (let r = 1; r < v.length; r++) {
    const row = v[r];
    if (String(row[iUid]).trim() !== want) continue;

    let fullName = '';
    if (iName != null) {
      fullName = String(row[iName] || '').trim();
    }

    if (!fullName && (iForename != null || iSurname != null)) {
      const fn = iForename != null ? String(row[iForename] || '').trim() : '';
      const sn = iSurname  != null ? String(row[iSurname]  || '').trim() : '';
      fullName = [fn, sn].filter(Boolean).join(' ');
    }

    const email = String(row[iEmail] || '').trim();

    return {
      owner_name: fullName || 'QAcademy Student',
      owner_email: email
    };
  }

  throw new Error('User not found');
}

function maskEmail_(email) {
  const s = String(email || '').trim();
  const at = s.indexOf('@');
  if (at <= 1) return 'email_hidden';

  const local = s.slice(0, at);
  const domain = s.slice(at + 1);

  const visible = Math.min(3, local.length);
  return local.slice(0, visible) + '***@' + domain;
}

function buildOwnerLabel_(name, emailMask) {
  const nm = String(name || '').trim() || 'QAcademy Student';
  const em = String(emailMask || '').trim();
  return em
    ? `Prepared for: ${nm} (${em})`
    : `Prepared for: ${nm}`;
}

/* ==================== UTILITIES ==================== */

function sanitizeStringArray_(arr) {
  if (!Array.isArray(arr)) return [];
  const out = [];
  arr.forEach(x => {
    const s = String(x || '').trim();
    if (s) out.push(s);
  });
  return out;
}

function readRawPayload_(e) {
  // Supports either: payload=<json> OR raw JSON in body
  return (e.parameter && e.parameter.payload)
    ? String(e.parameter.payload)
    : (e.postData && e.postData.contents) ? String(e.postData.contents) : '';
}

function json_(obj) {
  return ContentService.createTextOutput(JSON.stringify(obj))
    .setMimeType(ContentService.MimeType.JSON);
}

function jsonError_(message, code) {
  const payload = { ok: false, error: String(message || 'Error'), code: Number(code || 500) };
  return ContentService.createTextOutput(JSON.stringify(payload))
    .setMimeType(ContentService.MimeType.JSON);
}

function reqParam_(e, key) {
  const v = (e.parameter && e.parameter[key]) ? String(e.parameter[key]).trim() : '';
  if (!v) throw new Error(`Missing parameter: ${key}`);
  return v;
}

function must_(v, msg) {
  if (v === undefined || v === null || String(v).trim() === '') throw new Error(msg || 'Missing required value');
  return v;
}

function same_(a, b) { return norm_(a) === norm_(b); }
function norm_(s) { return String(s || '').trim().toLowerCase(); }

function mainTopic_(topic) {
  const t = String(topic || '').trim();
  if (!t) return '';
  const idx = t.indexOf(':');
  return (idx >= 0) ? t.slice(0, idx).trim() : t;
}

function colIndex_(header, name) {
  const idx = header.indexOf(String(name).toLowerCase());
  if (idx < 0) throw new Error(`Missing column: ${name}`);
  return idx;
}
function colIndexOptional_(header, name) {
  const idx = header.indexOf(String(name).toLowerCase());
  return idx >= 0 ? idx : -1;
}
function getCell_(row, idx) { return (idx >= 0 && idx < row.length) ? row[idx] : ''; }

function clampInt_(n, min, max) {
  n = parseInt(n, 10);
  if (isNaN(n)) n = min;
  return Math.max(min, Math.min(max, n));
}

function makeSeed_() { return String(new Date().getTime()); }

function sample_(arr, n, seedStr) {
  const a = arr.slice();
  let seed = 0;
  for (let i = 0; i < seedStr.length; i++) seed = (seed * 31 + seedStr.charCodeAt(i)) >>> 0;
  function rnd() {
    seed ^= seed << 13; seed >>>= 0;
    seed ^= seed >> 17; seed >>>= 0;
    seed ^= seed << 5;  seed >>>= 0;
    return (seed >>> 0) / 0xFFFFFFFF;
  }
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(rnd() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a.slice(0, n);
}

function isTruthy_(v) {
  if (typeof v === 'boolean') return v;
  const s = norm_(v);
  return (s === 'true' || s === 'yes' || s === 'y' || s === '1');
}

function asDateOrNull_(cell) {
  if (!cell && cell !== 0) return null;
  if (cell instanceof Date) return cell;
  const s = String(cell).trim();
  if (!s) return null;
  const d = new Date(s);
  if (isNaN(d.getTime())) return null;
  return d;
}

function headerMap_(headerRow) {
  const H = {};
  headerRow.forEach((h,i) => H[String(h||'').trim().toLowerCase()] = i);
  return H;
}

// Simple per-request cache (Apps Script execution memory)
let __CFG_CACHE = null;

function getCfgMap_(ss) {
  if (__CFG_CACHE) return __CFG_CACHE;

  const sh = ss.getSheetByName(TAB_CONFIG);
  const map = Object.create(null);

  if (!sh) {
    __CFG_CACHE = map;
    return map;
  }

  const values = sh.getDataRange().getValues();
  if (!values || values.length < 2) {
    __CFG_CACHE = map;
    return map;
  }

  // Expect: key | value | note(optional)
  for (let r = 1; r < values.length; r++) {
    const k = String(values[r][0] || '').trim();
    if (!k) continue;
    map[k] = values[r][1];
  }

  __CFG_CACHE = map;
  return map;
}

function getCfgNumber_(ss, key, fallback, min, max) {
  const m = getCfgMap_(ss);
  const raw = (key in m) ? m[key] : null;

  let n = Number(raw);
  if (!isFinite(n)) n = Number(fallback);

  if (isFinite(min)) n = Math.max(min, n);
  if (isFinite(max)) n = Math.min(max, n);

  // Final safety: if still not finite, use fallback
  if (!isFinite(n)) n = Number(fallback);

  return n;
}

function getOfflineMaxQuestions_(ss, itemsLen) {
  // cap to DEFAULT_OFFLINE_MAX_QUESTIONS unless you change config
  // also cap to MAX_N_DEFAULT logic: cannot exceed items count
  const cfg = getCfgNumber_(ss, CFG_OFFLINE_MAX_QUESTIONS, DEFAULT_OFFLINE_MAX_QUESTIONS, 1, 500);
  const cap = Math.max(1, Math.min(cfg, itemsLen || cfg));
  return cap;
}

function getOfflinePacksPerCourse_(ss) {
  return getCfgNumber_(ss, CFG_OFFLINE_PACKS_PER_COURSE, DEFAULT_OFFLINE_PACKS_PER_COURSE, 1, 100);
}

function ensureHeader_(sh, expectedHeader) {
  const lastCol = Math.max(1, sh.getLastColumn());
  let header = sh.getRange(1, 1, 1, lastCol).getValues()[0].map(s => String(s).trim().toLowerCase());
  const needed = expectedHeader.filter(h => header.indexOf(String(h).toLowerCase()) < 0);

  if (needed.length) {
    sh.insertColumnsAfter(header.length || 1, needed.length);
    header = header.concat(needed.map(x => String(x).toLowerCase()));
    sh.getRange(1, 1, 1, header.length).setValues([header]);
  }
  return header;
}
